SELECT order_id, customer_id,
       ROW_NUMBER() OVER (PARTITION BY customer_id ORDER BY ordered_at) AS seq
FROM orders;

const orders = [{id: 1, cid: 100}, {id: 2, cid: 100}];
const numbered = orders.map((o, i) => ({...o, row_number: i + 1}));
console.log(numbered);

List<Map> orders = new ArrayList<>();
for (int i = 0; i < orders.size(); i++) {
    orders.get(i).put("row_number", i + 1);
}
